#include<cstdio>
typedef unsigned long long uLL;
inline uLL read()
{
	uLL res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(uLL x){if(x>9)print(x/10);putchar(x%10+'0');}
const uLL s=7650000000000000001ull,qwq=1e17;
int main()
{
	uLL n=read();n-=s%n;
	printf("%lld %lld\n",n+1,qwq+n);
}
